#include <bits/stdc++.h>
using namespace std;
int n,a[402],dp[402][402];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=n+1;i<=2*n;i++)
        a[i]=a[i-n];
    for(int len=2;len<=n;len++)
        for(int l=1;l<2*n;l++){
            int r=l+len-1;
            for(int k=l;k<r;k++)
                dp[l][r]=max(dp[l][r],dp[l][k]+dp[k+1][r]+a[l]*a[k+1]*a[r+1]);
        }
    int ans=0;
    for(int i=1;i<=n;i++)
        ans=max(ans,dp[i][i+n-1]);
    printf("%d",ans);
    return 0;
}
